// ─────────────────────────────────────────────
// Secure Session Manager backed by Android Keystore
// ─────────────────────────────────────────────
class SecureSessionManager(private val context: Context) {

    companion object {
        private const val KEYSTORE_ALIAS = "biometric_session_key"
        private const val ANDROID_KEYSTORE = "AndroidKeyStore"
        private const val PREFS_NAME = "secure_session_prefs"
        private const val KEY_ENCRYPTED_TOKEN = "encrypted_session_token"
        private const val KEY_IV = "session_iv"
        private const val KEY_BIOMETRIC_ENROLLED = "biometric_enrolled"
        private const val TRANSFORMATION = "AES/CBC/PKCS7Padding"
    }

    private val prefs: SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    /**
     * Generate (or retrieve) an AES key in Android Keystore that requires
     * biometric authentication every time it is used.
     */
    fun getOrCreateBiometricKey(): SecretKey {
        val keyStore = KeyStore.getInstance(ANDROID_KEYSTORE).apply { load(null) }
        keyStore.getKey(KEYSTORE_ALIAS, null)?.let { return it as SecretKey }

        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES, ANDROID_KEYSTORE
        )
        val spec = KeyGenParameterSpec.Builder(
            KEYSTORE_ALIAS,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_CBC)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_PKCS7)
            .setUserAuthenticationRequired(true)
            .setInvalidatedByBiometricEnrollment(true)
            // Require auth for every use (timeout = 0)
            .setUserAuthenticationParameters(0, KeyProperties.AUTH_BIOMETRIC_STRONG)
            .build()

        keyGenerator.init(spec)
        return keyGenerator.generateKey()
    }

    /**
     * Return a Cipher configured for encryption – caller must pass it to
     * BiometricPrompt so the Keystore unlocks the key.
     */
    fun getEncryptionCipher(): Cipher {
        val cipher = Cipher.getInstance(TRANSFORMATION)
        cipher.init(Cipher.ENCRYPT_MODE, getOrCreateBiometricKey())
        return cipher
    }

    /**
     * Return a Cipher configured for decryption using the stored IV.
     */
    fun getDecryptionCipher(): Cipher? {
        val ivString = prefs.getString(KEY_IV, null) ?: return null
        val iv = Base64.decode(ivString, Base64.NO_WRAP)
        val cipher = Cipher.getInstance(TRANSFORMATION)
        cipher.init(Cipher.DECRYPT_MODE, getOrCreateBiometricKey(), IvParameterSpec(iv))
        return cipher
    }

    /**
     * After biometric-authenticated encryption, persist the ciphertext + IV.
     */
    fun storeEncryptedSessionToken(cipher: Cipher, sessionToken: String) {
        val encrypted = cipher.doFinal(sessionToken.toByteArray(Charsets.UTF_8))
        prefs.edit()
            .putString(KEY_ENCRYPTED_TOKEN, Base64.encodeToString(encrypted, Base64.NO_WRAP))
            .putString(KEY_IV, Base64.encodeToString(cipher.iv, Base64.NO_WRAP))
            .putBoolean(KEY_BIOMETRIC_ENROLLED, true)
            .apply()
    }

    /**
     * After biometric-authenticated decryption, recover the session token.
     */
    fun decryptSessionToken(cipher: Cipher): String? {
        val encryptedString = prefs.getString(KEY_ENCRYPTED_TOKEN, null) ?: return null
        val encrypted = Base64.decode(encryptedString, Base64.NO_WRAP)
        val decrypted = cipher.doFinal(encrypted)
        return String(decrypted, Charsets.UTF_8)
    }

    fun isBiometricEnrolled(): Boolean = prefs.getBoolean(KEY_BIOMETRIC_ENROLLED, false)

    fun hasEncryptedToken(): Boolean = prefs.getString(KEY_ENCRYPTED_TOKEN, null) != null

    fun clearSession() {
        prefs.edit().clear().apply()
        try {
            val keyStore = KeyStore.getInstance(ANDROID_KEYSTORE).apply { load(null) }
            keyStore.deleteEntry(KEYSTORE_ALIAS)
        } catch (_: Exception) {
        }
    }
}

