        setContentView(root)
    }

    private fun refreshUI() {
        val canBiometric = canUseBiometric()
        val enrolled = sessionManager.isBiometricEnrolled() && sessionManager.hasEncryptedToken()

        biometricButton.visibility = if (canBiometric && enrolled) View.VISIBLE else View.GONE
        enrollBiometricButton.visibility = if (canBiometric && !enrolled) View.VISIBLE else View.GONE

        statusText.text = when {
            !canBiometric -> "Biometric not available – use password."
            enrolled -> "Tap fingerprint button for quick login."
            else -> "Log in with password, then enable biometric."
        }
    }

    // ── Biometric availability check ─────────────────────────
    private fun canUseBiometric(): Boolean {
        val bm = BiometricManager.from(this)
        return bm.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG) ==
                BiometricManager.BIOMETRIC_SUCCESS
    }

    // ── BiometricPrompt setup ────────────────────────────────
    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    val crypto = result.cryptoObject
                    val cipher = crypto?.cipher
                    if (cipher == null) {
                        showToast("Crypto error – please use password.")
