class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val sessionToken = intent.getStringExtra("SESSION_TOKEN") ?: "none"

        val root = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
        }

        val welcome = TextView(this).apply {
            text = "Welcome! You are authenticated.\n\nSession: $sessionToken"
            textSize = 18f
        }
        root.addView(welcome)

        val logoutButton = Button(this).apply { text = "Logout" }
        logoutButton.setOnClickListener {
            SecureSessionManager(this@MainActivity).clearSession()
            startActivity(Intent(this@MainActivity, LoginActivity::class.java).apply {
                flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
            })
            finish()
        }
        root.addView(logoutButton)

        setContentView(root)
